mapper.select:
select userID, userpwd, username, tel, email
from user where
userID = #{userID}

mapper.update:
 update user set username=#{username},
		tel=#{tel},
		email=#{email} where userID=#{userID} and userpwd=#{userpwd}

mapper.select:
select b.no, b.subject, b.lat, b.lng, b.addrtitle, b.season
from `like` l join board b ON l.no = b.no
where l.userID = #{userID}

select no, userID, subject, context, hit, writedate,
thumbnail, season, lat, lng, addrtitle
from board
where userID=#{userID}
order by no desc
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM comment
WHERE userID = #{userID}
